noncompliant:
// Noncompliant: Exception passed as message argument
try
{
    DoSomething();
}
catch (Exception ex)
{
    logger.LogError("Error: {0}", ex); // Noncompliant - exception should be separate parameter
}

// Noncompliant: LogLevel passed as argument instead of parameter
var level = LogLevel.Error;
logger.Log(LogLevel.Information, "Level: {0}", level); // Noncompliant

compliant:
// Compliant: Exception passed as separate parameter
try
{
    DoSomething();
}
catch (Exception ex)
{
    logger.LogError(ex, "Error occurred"); // Compliant
}

// Compliant: LogLevel used as method parameter
logger.LogError("Error message"); // Compliant
logger.Log(LogLevel.Error, "Error message"); // Compliant
